const generatedArticle = $('Generate Content with Groq AI').item.json.choices[0].message.content;

// Create the SEO quality control prompt with toolstack focus
const systemPrompt = `You are a senior SEO strategist and content editor. Your mission is to review and improve the generated article to ensure it:

1. TOOLSTACK ALIGNMENT (CRITICAL - DO THIS FIRST):
   - Scan all tool mentions. KEEP ONLY: n8n, Groq, Claude, ChatGPT, Databricks, Snowflake, PostgreSQL, MongoDB, Apache Kafka, Astro, React, Python, GitHub, Netlify, Docker, Slack, Postman, Power BI, Looker, Google Analytics, Microsoft Clarity, AWS, Google Cloud, Azure, DigitalOcean, Apify, Home Assistant, Raycast, Linear, Notion, etc.
   - REMOVE: IFTTT, Wave, FreshBooks, Hootsuite, Buffer, Apache Airflow, Tableau, Miro, Figma
   - REPLACE generic tools with Emil's actual tools (e.g., replace "Wave" with "Databricks", "Apache Airflow" with "n8n", "Tableau" with "Power BI")
   - INTEGRATE tools naturally showing how they work TOGETHER (n8n + Groq + Slack, or Databricks + PostgreSQL + Power BI)
   - ADD more toolstack references to increase authenticity and E-A-T

2. Google's guidelines (E-E-A-T, people-first, helpful content):
   - Experience: Use REAL toolstack examples demonstrating authentic expertise
   - Expertise: Technical depth with specific tool names and real use cases
   - Authoritativeness: Confident, informed tone using Emil's actual tools
   - Trustworthiness: Honest about tool capabilities, no exaggerations

3. Quality standards:
   - Clear structure with H2/H3 headings
   - No keyword stuffing, remove repetition
   - Search intent coverage - answer all user questions
   - Natural internal linking opportunities

RETURN PURE MARKDOWN ONLY - no JSON or code blocks.

Prioritize toolstack authenticity above all else. Make the article credible through real tool references.`;

const userPrompt = `Review and improve this article for toolstack alignment (prioritize this), Google guidelines, and quality. Make tool references AUTHENTIC to Emil's actual toolstack:\n\n${generatedArticle}`;

return {
  systemPrompt: systemPrompt,
  userPrompt: userPrompt
};

// Extract the generated content from Groq response
const response = $input.item.json;
const rawContent = response.choices[0].message.content;

// Extract SEO title and meta description
const seoTitleMatch = rawContent.match(/SEO_TITLE:\s*(.+?)\n/);
const metaDescMatch = rawContent.match(/META_DESC:\s*(.+?)\n/);

// Remove the SEO lines from content
let content = rawContent
  .replace(/SEO_TITLE:\s*.+?\n/, '')
  .replace(/META_DESC:\s*.+?\n/, '')
  .trim();

const seoTitle = seoTitleMatch ? seoTitleMatch[1].trim() : $('Pick Random Keyword').item.json.keyword;
let metaDescription = metaDescMatch ? metaDescMatch[1].trim() : '';

// CRITICAL: Validate and truncate meta description to max 155 characters
if (metaDescription.length > 155) {
  console.log(`WARNING: Meta description too long (${metaDescription.length} chars). Truncating to 155.`);
  metaDescription = metaDescription.substring(0, 152) + '...';
}

// Extract H1 title from content (for frontmatter)
const h1Match = content.match(/^#\s*(.+?)\n/);
const title = h1Match ? h1Match[1].trim() : seoTitle;

// CRITICAL: Remove H1 from content since Astro layout displays title from frontmatter
// This prevents duplicate H1 headers on the page
if (h1Match) {
  content = content.replace(/^#\s*.+?\n\n?/, '').trim();
}

// Create slug from keyword
const slug = $('Pick Random Keyword').item.json.keyword
  .toLowerCase()
  .replace(/[åäö]/g, match => ({ 'å': 'a', 'ä': 'a', 'ö': 'o' }[match]))
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '');

// Get current date for filename
const now = new Date();
const date = now.toISOString().split('T')[0];
const publishDate = now.toLocaleDateString('sv-SE');

// Create excerpt from first paragraph (after H1 removal)
const firstParagraph = content.split('\n\n')[0] || content.substring(0, 200);
const excerpt = firstParagraph.length > 150 ? firstParagraph.substring(0, 147) + '...' : firstParagraph;

// Escape YAML strings
const escapeYaml = (str) => str.replace(/'/g, "''");

return {
  content: content,
  title: title,
  seoTitle: seoTitle,
  metaDescription: metaDescription,
  excerpt: excerpt,
  slug: slug,
  keyword: $('Pick Random Keyword').item.json.keyword,
  category: $('Pick Random Keyword').item.json.category,
  publishDate: publishDate,
  filename: `${slug}.md`
};

// Create complete Astro markdown with frontmatter
const data = $input.item.json;

// Auto-generate tags based on keyword and category
const baseTags = [];
if (data.category) baseTags.push(data.category);

// Add intelligent tags based on content
const contentLower = data.content.toLowerCase();
const tagMap = {
  'data engineering': ['Data Engineering', 'Modern Data Stack'],
  'python': ['Python'],
  'databricks': ['Databricks'],
  'ai': ['Artificial Intelligence', 'AI'],
  'automation': ['Automation'],
  'astro': ['Astro', 'Web Development'],
  'analytics': ['Analytics', 'Business Intelligence'],
  'cloud': ['Cloud Platforms'],
  'n8n': ['Automation', 'Workflow'],
  'sql': ['SQL', 'Data Engineering']
};

Object.entries(tagMap).forEach(([keyword, tags]) => {
  if (contentLower.includes(keyword)) {
    tags.forEach(tag => {
      if (!baseTags.includes(tag)) baseTags.push(tag);
    });
  }
});

// Limit to 5 tags
const tags = baseTags.slice(0, 5);

const escapeYaml = (str) => str.replace(/'/g, "''");

const markdown = `---
title: '${escapeYaml(data.title)}'
excerpt: '${escapeYaml(data.excerpt)}'
publishDate: '${data.publishDate}'
tags:
${tags.map(tag => `  - ${escapeYaml(tag)}`).join('\n')}
isFeatured: false
hidden: true
seo:
  title: '${escapeYaml(data.seoTitle)} | Emil Karlsson'
  description: '${escapeYaml(data.metaDescription)}'
  image:
    src: '/hero-desktop.jpg'
    alt: 'Emil Karlsson'
---

${data.content}
`;

return {
  finalContent: markdown,
  draft_content: markdown,
  title: data.title,
  slug: data.slug,
  keyword: data.keyword,
  filename: data.filename,
  seoTitle: data.seoTitle,
  metaDescription: data.metaDescription,
  tags: tags
};

// Generate Emil-specific personal insights to add authenticity & E-A-T
const article = $('Build Final Markdown').item.json.finalContent;
const keyword = $('Build Final Markdown').item.json.keyword;

const systemPrompt = `You are helping add authentic, personal insights from Emil Karlsson to make the article more credible and people-first.

Emil's expertise areas:
- Data engineering with Databricks, Snowflake, Kafka
- Automation with n8n, OpenClaw (self-built AI content/workflow engine on Hetzner)
- AI integration with Groq, Claude
- Self-hosted AI stack: Coolify, LiteLLM, Minio, n8n, OpenClaw
- Web development with Astro, React
- Building modern data stacks

Add 1-2 personal perspective callouts like:
- "In my experience with [TOOL]..."
- "When I built [PROJECT], I learned..."
- "A pattern I've noticed..."
- "The mistake I made initially..."

These should be specific, credible, and feel authentic from Emil's years of experience.`;

const userPrompt = `Article keyword: "${keyword}"\n\nAdd 1-2 authentic personal insights from Emil's perspective. These should:\n1. Feel genuine and specific (not generic)\n2. Relate to the article topic\n3. Be short callout-style additions\n4. Show practical experience, not just theory\n\nReturn ONLY the insights as plain text, one per line, formatted as:\n"In my experience [insight]"\nor\n"A pattern I've noticed [insight]"\n\nArticle:\n${article.substring(0, 1000)}...`;

return {
  systemPrompt: systemPrompt,
  userPrompt: userPrompt,
  keyword: keyword,
  slug: $('Build Final Markdown').item.json.slug
};

// Create comprehensive quality checklist for human review
const article = $('Build Final Markdown').item.json.finalContent;
const seoTitle = $('Build Final Markdown').item.json.seoTitle;
const metaDesc = $('Build Final Markdown').item.json.metaDescription;
const keyword = $('Build Final Markdown').item.json.keyword;
const insights = $('Groq: Generate Insights').item.json.choices?.[0]?.message?.content || 'No insights generated';

// Quality checks
const checks = {
  content_length: article.length > 1000,
  has_h2_headings: (article.match(/^## /gm) || []).length >= 2,
  has_key_takeaways: article.includes('Key Takeaways'),
  has_cta: article.includes('[reach out](/contact)') || article.includes('[articles on my blog](/blog)'),
  keyword_in_title: seoTitle.toLowerCase().includes(keyword.toLowerCase()),
  meta_desc_length: metaDesc.length > 80 && metaDesc.length <= 155,
  no_excessive_keywords: (article.match(new RegExp(keyword, 'gi')) || []).length < 15,
  has_code_examples: article.includes('`'),
  references_toolstack: article.match(/n8n|Groq|Databricks|Astro|Netlify|PostgreSQL|Kafka|Claude|ChatGPT/gi) ? (article.match(/n8n|Groq|Databricks|Astro|Netlify|PostgreSQL|Kafka|Claude|ChatGPT/gi) || []).length >= 3 : false,
  insights_generated: insights.length > 50
};

// Score E-A-T (1-10)
let eatScore = 5;
if (checks.references_toolstack) eatScore += 2;
if (checks.has_code_examples) eatScore += 1;
if (checks.no_excessive_keywords) eatScore += 1;
if (checks.insights_generated) eatScore += 1;

const passedChecks = Object.values(checks).filter(v => v).length;
const totalChecks = Object.keys(checks).length;

return {
  quality_checks: checks,
  passed_checks: passedChecks,
  total_checks: totalChecks,
  quality_percentage: Math.round((passedChecks / totalChecks) * 100),
  eat_score: Math.min(10, eatScore),
  insights: insights,
  keyword: keyword,
  slug: $('Build Final Markdown').item.json.slug,
  ready_for_review: passedChecks >= 8 // 8+ checks passed = ready
};

// Build enhanced markdown with frontmatter including E-A-T, disclosure, author, JSON-LD schema
const data = $('Build Final Markdown').item.json;
const checklist = $('Generate Quality Checklist').item.json;
const insights = checklist.insights;

// Add Emil's personal insights to article
let enhancedContent = data.finalContent;
if (insights && insights.length > 100) {
  const insightSection = `\n\n> **💡 From Emil's Experience**\n> ${insights.split('\n').filter(l => l.trim()).join('\n> ')}\n\n`;
  // Insert after intro
  const parts = enhancedContent.split('\n\n');
  if (parts.length > 2) {
    parts.splice(2, 0, insightSection.trim());
    enhancedContent = parts.join('\n\n');
  }
}

// Create JSON-LD schema for E-A-T
const jsonLd = {
  '@context': 'https://schema.org',
  '@type': 'BlogPosting',
  headline: data.seoTitle,
  description: data.metaDescription,
  author: {
    '@type': 'Person',
    name: 'Emil Karlsson',
    url: 'https://www.emilingemarkarlsson.com',
    jobTitle: 'Data Engineer & Automation Specialist',
    image: 'https://www.emilingemarkarlsson.com/hero-desktop.jpg'
  },
  datePublished: new Date().toISOString(),
  dateModified: new Date().toISOString(),
  keywords: data.keyword,
  image: {
    '@type': 'ImageObject',
    url: 'https://www.emilingemarkarlsson.com/hero-desktop.jpg'
  }
};

const frontmatter = `---
title: '${data.title}'
excerpt: '${data.excerpt}'
publishDate: '${data.publishDate}'
updatedDate: '${new Date().toLocaleDateString('sv-SE')}'
author: 'Emil Karlsson'
authorUrl: 'https://www.emilingemarkarlsson.com'
authorBio: 'Data engineer, full-stack developer, and AI automation specialist based in Stockholm.'
tags:
${data.tags.map(tag => `  - ${tag}`).join('\n')}
isFeatured: false
hidden: true
quality_score: ${checklist.eat_score}/10
seo:
  title: '${data.seoTitle} | Emil Karlsson'
  description: '${data.metaDescription}'
  image:
    src: '/hero-desktop.jpg'
    alt: 'Emil Karlsson'
schema:
  ${JSON.stringify(jsonLd).split(',').join(',\n  ')}
disclosure: 'This article was AI-assisted using Groq (LLaMA 3.1 405B) and Claude, with human writing and review by Emil Karlsson. Views and insights are from Emil\'s professional experience.'
---

${enhancedContent}`;

return {
  finalMarkdown: frontmatter,
  title: data.title,
  slug: data.slug,
  keyword: data.keyword,
  quality_score: checklist.eat_score,
  passed_checks: `${checklist.passed_checks}/${checklist.total_checks}`,
  ready_for_review: checklist.ready_for_review
};

const slug   = $('Build Enhanced Markdown (E-A-T)').item.json.slug;
const kw     = $('Build Enhanced Markdown (E-A-T)').item.json.keyword;
const title  = $('Build Enhanced Markdown (E-A-T)').item.json.title;
const date   = new Date().toISOString().split('T')[0];
const rand   = Math.floor(Math.random() * 1000000).toString().padStart(6, '0');
const filename = `${date}-${slug}-${rand}.md`;

const webhookBase = 'https://n8n.theunnamedroads.com/webhook/seo-approve';
const approveUrl  = `${webhookBase}?action=approve&filename=${encodeURIComponent(filename)}&slug=${encodeURIComponent(slug)}&keyword=${encodeURIComponent(kw)}`;
const rejectUrl   = `${webhookBase}?action=reject&filename=${encodeURIComponent(filename)}&slug=${encodeURIComponent(slug)}`;
const previewUrl  = `https://minio-api.thehockeyanalytics.com/eik-seo-drafts/${filename}`;

return { filename, slug, kw, title, approveUrl, rejectUrl, previewUrl };

const u    = $input.item.json;
const meta = $('Build Enhanced Markdown (E-A-T)').item.json;
const kw   = $('Pick Random Keyword').item.json;
const fmt  = $('Format & Extract Metadata').item.json;

const text = [
  '📋 <b>Ny SEO-artikel – emilingemarkarlsson.com</b>',
  '',
  '<b>Titel:</b> ' + (meta.title || ''),
  '<b>Keyword:</b> ' + (meta.keyword || ''),
  '<b>Slug:</b> /blog/' + (meta.slug || ''),
  '<b>Kategori:</b> ' + (kw.category || '–'),
  '',
  '<b>Kvalitet:</b> ' + (meta.quality_score || '?') + '/10 – ' + (meta.passed_checks || '?') + ' kontroller',
  '',
  '<b>Meta:</b>',
  (fmt.metaDescription || ''),
  '',
  '📖 <a href="' + u.previewUrl + '">Granska utkast</a>',
].join('\n');

return { json: { ...u, telegramText: text, approveUrl: u.approveUrl, rejectUrl: u.rejectUrl } };

